17: )
18: 
19: // DetectLibsCves fills LibraryScanner information
20: func DetectLibsCves(r *models.ScanResult, cacheDir string, noProgress bool) (err error) {
21: 	totalCnt := 0
22: 	if len(r.LibraryScanners) == 0 {
23: 		return
24: 	}
25: 
26: 	// initialize trivy's logger and db
27: 	err = log.InitLogger(false, false)
28: 	if err != nil {
29: 		return err
30: 	}
31: 
32: 	logging.Log.Info("Updating library db...")
33: 	if err := downloadDB("", cacheDir, noProgress, false); err != nil {
34: 		return err
35: 	}
36: 
37: 	if err := trivydb.Init(cacheDir); err != nil {
38: 		return err
39: 	}
40: 	defer trivydb.Close()
41: 
42: 	for _, lib := range r.LibraryScanners {
43: 		vinfos, err := lib.Scan()
44: 		if err != nil {
45: 			return err
46: 		}
47: 		for _, vinfo := range vinfos {
48: 			vinfo.Confidences.AppendIfMissing(models.TrivyMatch)
49: 			if v, ok := r.ScannedCves[vinfo.CveID]; !ok {
50: 				r.ScannedCves[vinfo.CveID] = vinfo
51: 			} else {
52: 				v.LibraryFixedIns = append(v.LibraryFixedIns, vinfo.LibraryFixedIns...)
53: 				r.ScannedCves[vinfo.CveID] = v
54: 			}
55: 		}
56: 		totalCnt += len(vinfos)
57: 	}
58: 
59: 	logging.Log.Infof("%s: %d CVEs are detected with Library",
60: 		r.FormatServerName(), totalCnt)
61: 
62: 	return nil
63: }
64: 
65: func downloadDB(appVersion, cacheDir string, quiet, skipUpdate bool) error {
66: 	client := db.NewClient(cacheDir, quiet, false)
67: 	ctx := context.Background()
68: 	needsUpdate, err := client.NeedsUpdate(appVersion, skipUpdate)
69: 	if err != nil {
70: 		return xerrors.Errorf("database error: %w", err)
71: 	}
72: 
73: 	if needsUpdate {
74: 		logging.Log.Info("Need to update DB")
75: 		logging.Log.Info("Downloading DB...")
76: 		if err := client.Download(ctx, cacheDir); err != nil {
77: 			return xerrors.Errorf("failed to download vulnerability DB: %w", err)
78: 		}
79: 	}
80: 
81: 	// for debug
82: 	if err := showDBInfo(cacheDir); err != nil {
83: 		return xerrors.Errorf("failed to show database info: %w", err)
84: 	}
85: 	return nil
86: }
87: 
88: func showDBInfo(cacheDir string) error {
89: 	m := metadata.NewClient(cacheDir)
90: 	meta, err := m.Get()
91: 	if err != nil {
92: 		return xerrors.Errorf("something wrong with DB: %w", err)
93: 	}
94: 	log.Logger.Debugf("DB Schema: %d, UpdatedAt: %s, NextUpdate: %s, DownloadedAt: %s",
95: 		meta.Version, meta.UpdatedAt, meta.NextUpdate, meta.DownloadedAt)
96: 	return nil
97: }
