121: func (l *base) runningKernel() (release, version string, err error) {
122: 	r := l.exec("uname -r", noSudo)
123: 	if !r.isSuccess() {
124: 		return "", "", xerrors.Errorf("Failed to SSH: %s", r)
125: 	}
126: 	release = strings.TrimSpace(r.Stdout)
127: 
128: 	switch l.Distro.Family {
129: 	case constant.Debian:
130: 		r := l.exec("uname -a", noSudo)
131: 		if !r.isSuccess() {
132: 			return "", "", xerrors.Errorf("Failed to SSH: %s", r)
133: 		}
134: 		ss := strings.Fields(r.Stdout)
135: 		if 6 < len(ss) {
136: 			version = ss[6]
137: 		}
138: 		if _, err := debver.NewVersion(version); err != nil {
139: 			l.log.Warnf("kernel running version is invalid. skip kernel vulnerability detection. actual kernel version: %s, err: %s", version, err)
140: 			version = ""
141: 		}
142: 	}
143: 	return
144: }
