146: func (l *base) allContainers() (containers []config.Container, err error) {
147: 	switch l.ServerInfo.ContainerType {
148: 	case "", "docker":
149: 		stdout, err := l.dockerPs("-a --format '{{.ID}} {{.Names}} {{.Image}}'")
150: 		if err != nil {
151: 			return containers, err
152: 		}
153: 		return l.parseDockerPs(stdout)
154: 	case "lxd":
155: 		stdout, err := l.lxdPs("-c n")
156: 		if err != nil {
157: 			return containers, err
158: 		}
159: 		return l.parseLxdPs(stdout)
160: 	case "lxc":
161: 		stdout, err := l.lxcPs("-1")
162: 		if err != nil {
163: 			return containers, err
164: 		}
165: 		return l.parseLxcPs(stdout)
166: 	default:
167: 		return containers, xerrors.Errorf(
168: 			"Not supported yet: %s", l.ServerInfo.ContainerType)
169: 	}
170: }
