253: 	for _, line := range lines {
254: 		fields := strings.Fields(line)
255: 		if len(fields) == 0 {
256: 			break
257: 		}
258: 		if len(fields) != 3 {
259: 			return containers, xerrors.Errorf("Unknown format: %s", line)
260: 		}
261: 		containers = append(containers, config.Container{
262: 			ContainerID: fields[0],
263: 			Name:        fields[1],
264: 			Image:       fields[2],
265: 		})
266: 	}
267: 	return
268: }
