307: func (l *base) ip() ([]string, []string, error) {
308: 	// e.g.
309: 	// 2: eth0: <BROADCAST,MULTICAST,UP,LOWER_UP> mtu 1500 qdisc pfifo_fast state UP qlen 1000\    link/ether 52:54:00:2a:86:4c brd ff:ff:ff:ff:ff:ff
310: 	// 2: eth0    inet 10.0.2.15/24 brd 10.0.2.255 scope global eth0
311: 	// 2: eth0    inet6 fe80::5054:ff:fe2a:864c/64 scope link \       valid_lft forever preferred_lft forever
312: 	r := l.exec("/sbin/ip -o addr", noSudo)
313: 	if !r.isSuccess() {
314: 		return nil, nil, xerrors.Errorf("Failed to detect IP address: %v", r)
315: 	}
316: 	ipv4Addrs, ipv6Addrs := l.parseIP(r.Stdout)
317: 	return ipv4Addrs, ipv6Addrs, nil
318: }
