320: // parseIP parses the results of ip command
321: func (l *base) parseIP(stdout string) (ipv4Addrs []string, ipv6Addrs []string) {
322: 	lines := strings.Split(stdout, "\n")
323: 	for _, line := range lines {
324: 		fields := strings.Fields(line)
325: 		if len(fields) < 4 {
326: 			continue
327: 		}
328: 		ip, _, err := net.ParseCIDR(fields[3])
329: 		if err != nil {
330: 			continue
331: 		}
332: 		if !ip.IsGlobalUnicast() {
333: 			continue
334: 		}
335: 		if ipv4 := ip.To4(); ipv4 != nil {
336: 			ipv4Addrs = append(ipv4Addrs, ipv4.String())
337: 		} else {
338: 			ipv6Addrs = append(ipv6Addrs, ip.String())
339: 		}
340: 	}
341: 	return
342: }
