395: func (l *base) detectRunningOnAws() (ok bool, instanceID string, err error) {
396: 	if r := l.exec("type curl", noSudo); r.isSuccess() {
397: 		cmd := "curl --max-time 1 --noproxy 169.254.169.254 http://169.254.169.254/latest/meta-data/instance-id"
398: 		r := l.exec(cmd, noSudo)
399: 		if r.isSuccess() {
400: 			id := strings.TrimSpace(r.Stdout)
401: 			if !l.isAwsInstanceID(id) {
402: 				return false, "", nil
403: 			}
404: 			return true, id, nil
405: 		}
406: 
407: 		switch r.ExitStatus {
408: 		case 28, 7:
409: 			// Not running on AWS
410: 			//  7   Failed to connect to host.
411: 			// 28  operation timeout.
412: 			return false, "", nil
413: 		}
414: 	}
415: 
416: 	if r := l.exec("type wget", noSudo); r.isSuccess() {
417: 		cmd := "wget --tries=3 --timeout=1 --no-proxy -q -O - http://169.254.169.254/latest/meta-data/instance-id"
418: 		r := l.exec(cmd, noSudo)
419: 		if r.isSuccess() {
420: 			id := strings.TrimSpace(r.Stdout)
421: 			if !l.isAwsInstanceID(id) {
422: 				return false, "", nil
423: 			}
424: 			return true, id, nil
425: 		}
426: 
427: 		switch r.ExitStatus {
428: 		case 4, 8:
429: 			// Not running on AWS
430: 			// 4   Network failure
431: 			// 8   Server issued an error response.
432: 			return false, "", nil
433: 		}
434: 	}
435: 	return false, "", xerrors.Errorf(
436: 		"Failed to curl or wget to AWS instance metadata on %s. container: %s",
437: 		l.ServerInfo.ServerName, l.ServerInfo.Container.Name)
438: }
439: 
440: // http://docs.aws.amazon.com/AWSEC2/latest/UserGuide/resource-ids.html
441: var awsInstanceIDPattern = regexp.MustCompile(`^i-[0-9a-f]+$`)
442: 
443: func (l *base) isAwsInstanceID(str string) bool {
444: 	return awsInstanceIDPattern.MatchString(str)
445: }
