518: // https://unix.stackexchange.com/questions/196166/how-to-find-out-if-a-system-uses-sysv-upstart-or-systemd-initsystem
519: func (l *base) detectInitSystem() (string, error) {
520: 	var f func(string) (string, error)
521: 	f = func(cmd string) (string, error) {
522: 		r := l.exec(cmd, sudo)
523: 		if !r.isSuccess() {
524: 			return "", xerrors.Errorf("Failed to stat %s: %s", cmd, r)
525: 		}
526: 		scanner := bufio.NewScanner(strings.NewReader(r.Stdout))
527: 		scanner.Scan()
528: 		line := strings.TrimSpace(scanner.Text())
529: 		if strings.Contains(line, "systemd") {
530: 			return systemd, nil
531: 		} else if strings.Contains(line, "upstart") {
532: 			return upstart, nil
533: 		} else if strings.Contains(line, "File: ‘/proc/1/exe’ -> ‘/sbin/init’") ||
534: 			strings.Contains(line, "File: `/proc/1/exe' -> `/sbin/init'") {
535: 			return f("stat /sbin/init")
536: 		} else if line == "File: ‘/sbin/init’" ||
537: 			line == "File: `/sbin/init'" {
538: 			r := l.exec("/sbin/init --version", noSudo)
539: 			if r.isSuccess() {
540: 				if strings.Contains(r.Stdout, "upstart") {
541: 					return upstart, nil
542: 				}
543: 			}
544: 			return sysVinit, nil
545: 		}
546: 		return "", xerrors.Errorf("Failed to detect a init system: %s", line)
547: 	}
548: 	return f("stat /proc/1/exe")
549: }
