571: // LibFile : library file content
572: type LibFile struct {
573: 	Contents []byte
574: 	Filemode os.FileMode
575: }
576: 
577: func (l *base) scanLibraries() (err error) {
578: 	if len(l.LibraryScanners) != 0 {
579: 		return nil
580: 	}
581: 
582: 	// library scan for servers need lockfiles
583: 	if len(l.ServerInfo.Lockfiles) == 0 && !l.ServerInfo.FindLock {
584: 		return nil
585: 	}
586: 
587: 	l.log.Info("Scanning Lockfile...")
588: 
589: 	libFilemap := map[string]LibFile{}
590: 	detectFiles := l.ServerInfo.Lockfiles
591: 
592: 	// auto detect lockfile
593: 	if l.ServerInfo.FindLock {
594: 		findopt := ""
595: 		for filename := range models.LibraryMap {
596: 			findopt += fmt.Sprintf("-name %q -o ", filename)
597: 		}
598: 
599: 		// delete last "-o "
600: 		// find / -type f -and \( -name "package-lock.json" -o -name "yarn.lock" ... \) 2>&1 | grep -v "find: "
601: 		cmd := fmt.Sprintf(`find / -type f -and \( ` + findopt[:len(findopt)-3] + ` \) 2>&1 | grep -v "find: "`)
602: 		r := exec(l.ServerInfo, cmd, noSudo)
603: 		if r.ExitStatus != 0 && r.ExitStatus != 1 {
604: 			return xerrors.Errorf("Failed to find lock files")
605: 		}
606: 		detectFiles = append(detectFiles, strings.Split(r.Stdout, "\n")...)
607: 	}
608: 
609: 	for _, path := range detectFiles {
610: 		if path == "" {
611: 			continue
612: 		}
613: 
614: 		if path, err = filepath.Abs(path); err != nil {
615: 			return xerrors.Errorf("Failed to abs the lockfile. err: %w, filepath: %s", err, path)
616: 		}
617: 
618: 		// skip already exist
619: 		if _, ok := libFilemap[path]; ok {
620: 			continue
621: 		}
622: 
623: 		var f LibFile
624: 		switch l.Distro.Family {
625: 		case constant.ServerTypePseudo:
626: 			fileinfo, err := os.Stat(path)
627: 			if err != nil {
628: 				return xerrors.Errorf("Failed to get target file info. err: %w, filepath: %s", err, path)
629: 			}
630: 			f.Filemode = fileinfo.Mode().Perm()
631: 			f.Contents, err = os.ReadFile(path)
632: 			if err != nil {
633: 				return xerrors.Errorf("Failed to read target file contents. err: %w, filepath: %s", err, path)
634: 			}
635: 		default:
636: 			cmd := fmt.Sprintf(`stat -c "%%a" %s`, path)
637: 			r := exec(l.ServerInfo, cmd, noSudo)
638: 			if !r.isSuccess() {
639: 				return xerrors.Errorf("Failed to get target file permission: %s, filepath: %s", r, path)
640: 			}
641: 			permStr := fmt.Sprintf("0%s", strings.ReplaceAll(r.Stdout, "\n", ""))
642: 			perm, err := strconv.ParseUint(permStr, 8, 32)
643: 			if err != nil {
644: 				return xerrors.Errorf("Failed to parse permission string. err: %w, permission string: %s", err, permStr)
645: 			}
646: 			f.Filemode = os.FileMode(perm)
647: 
648: 			cmd = fmt.Sprintf("cat %s", path)
649: 			r = exec(l.ServerInfo, cmd, noSudo)
650: 			if !r.isSuccess() {
651: 				return xerrors.Errorf("Failed to get target file contents: %s, filepath: %s", r, path)
652: 			}
653: 			f.Contents = []byte(r.Stdout)
654: 		}
655: 		libFilemap[path] = f
656: 	}
657: 
658: 	var libraryScanners []models.LibraryScanner
659: 	if libraryScanners, err = AnalyzeLibraries(context.Background(), libFilemap, l.ServerInfo.Mode.IsOffline()); err != nil {
660: 		return err
661: 	}
662: 	l.LibraryScanners = append(l.LibraryScanners, libraryScanners...)
663: 	return nil
664: }
665: 
666: // AnalyzeLibraries : detects libs defined in lockfile
667: func AnalyzeLibraries(ctx context.Context, libFilemap map[string]LibFile, isOffline bool) (libraryScanners []models.LibraryScanner, err error) {
668: 	// https://github.com/aquasecurity/trivy/blob/84677903a6fa1b707a32d0e8b2bffc23dde52afa/pkg/fanal/analyzer/const.go
669: 	disabledAnalyzers := []analyzer.Type{
670: 		// ======
671: 		//   OS
672: 		// ======
673: 		analyzer.TypeOSRelease,
674: 		analyzer.TypeAlpine,
675: 		analyzer.TypeAmazon,
676: 		analyzer.TypeCBLMariner,
677: 		analyzer.TypeDebian,
678: 		analyzer.TypePhoton,
679: 		analyzer.TypeCentOS,
680: 		analyzer.TypeRocky,
681: 		analyzer.TypeAlma,
682: 		analyzer.TypeFedora,
683: 		analyzer.TypeOracle,
684: 		analyzer.TypeRedHatBase,
685: 		analyzer.TypeSUSE,
686: 		analyzer.TypeUbuntu,
687: 
688: 		// OS Package
689: 		analyzer.TypeApk,
690: 		analyzer.TypeDpkg,
691: 		analyzer.TypeDpkgLicense,
692: 		analyzer.TypeRpm,
693: 		analyzer.TypeRpmqa,
694: 
695: 		// OS Package Repository
696: 		analyzer.TypeApkRepo,
697: 
698: 		// ============
699: 		// Image Config
700: 		// ============
701: 		analyzer.TypeApkCommand,
702: 
703: 		// =================
704: 		// Structured Config
705: 		// =================
706: 		analyzer.TypeYaml,
707: 		analyzer.TypeJSON,
708: 		analyzer.TypeDockerfile,
709: 		analyzer.TypeTerraform,
710: 		analyzer.TypeCloudFormation,
711: 		analyzer.TypeHelm,
712: 
713: 		// ========
714: 		// License
715: 		// ========
716: 		analyzer.TypeLicenseFile,
717: 
718: 		// ========
719: 		// Secrets
720: 		// ========
721: 		analyzer.TypeSecret,
722: 
723: 		// =======
724: 		// Red Hat
725: 		// =======
726: 		analyzer.TypeRedHatContentManifestType,
727: 		analyzer.TypeRedHatDockerfileType,
728: 	}
729: 	anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)
730: 
731: 	for path, f := range libFilemap {
732: 		var wg sync.WaitGroup
733: 		result := new(analyzer.AnalysisResult)
734: 		if err := anal.AnalyzeFile(
735: 			ctx,
736: 			&wg,
737: 			semaphore.NewWeighted(1),
738: 			result,
739: 			"",
740: 			path,
741: 			&DummyFileInfo{size: int64(len(f.Contents)), filemode: f.Filemode},
742: 			func() (dio.ReadSeekCloserAt, error) { return dio.NopCloser(bytes.NewReader(f.Contents)), nil },
743: 			nil,
744: 			analyzer.AnalysisOptions{Offline: isOffline},
745: 		); err != nil {
746: 			return nil, xerrors.Errorf("Failed to get libs. err: %w", err)
747: 		}
748: 		wg.Wait()
749: 
750: 		libscan, err := convertLibWithScanner(result.Applications)
751: 		if err != nil {
752: 			return nil, xerrors.Errorf("Failed to convert libs. err: %w", err)
753: 		}
754: 		libraryScanners = append(libraryScanners, libscan...)
755: 	}
756: 	return libraryScanners, nil
757: }
