983: func nativeScanPort(scanDest string) (bool, error) {
984: 	conn, err := net.DialTimeout("tcp", scanDest, time.Duration(1)*time.Second)
985: 	if err != nil {
986: 		if strings.Contains(err.Error(), "i/o timeout") || strings.Contains(err.Error(), "connection refused") {
987: 			return false, nil
988: 		}
989: 		if strings.Contains(err.Error(), "too many open files") {
990: 			time.Sleep(time.Duration(1) * time.Second)
991: 			return nativeScanPort(scanDest)
992: 		}
993: 		return false, err
994: 	}
995: 	conn.Close()
996: 
997: 	return true, nil
998: }
