1000: func (l *base) execExternalPortScan(scanDestIPPorts map[string][]string) ([]string, error) {
1001: 	portScanConf := l.getServerInfo().PortScan
1002: 	l.log.Infof("Using Port Scanner: External Scanner(PATH: %s)", portScanConf.ScannerBinPath)
1003: 	l.log.Infof("External Scanner Apply Options: Scan Techniques: %s, HasPrivileged: %t, Source Port: %s",
1004: 		strings.Join(portScanConf.ScanTechniques, ","), portScanConf.HasPrivileged, portScanConf.SourcePort)
1005: 	baseCmd := formatNmapOptionsToString(portScanConf)
1006: 
1007: 	listenIPPorts := []string{}
1008: 
1009: 	for ip, ports := range scanDestIPPorts {
1010: 		if !isLocalExec(l.ServerInfo.Port, l.ServerInfo.Host) && net.ParseIP(ip).IsLoopback() {
1011: 			continue
1012: 		}
1013: 
1014: 		_, cancel := context.WithTimeout(context.Background(), 5*time.Minute)
1015: 		defer cancel()
1016: 
1017: 		scanner, err := nmap.NewScanner(nmap.WithBinaryPath(portScanConf.ScannerBinPath))
1018: 		if err != nil {
1019: 			return []string{}, xerrors.Errorf("unable to create nmap scanner: %w", err)
1020: 		}
1021: 
1022: 		scanTechnique, err := l.setScanTechniques()
1023: 		if err != nil {
1024: 			return []string{}, err
1025: 		}
1026: 		scanner.AddOptions(scanTechnique)
1027: 
1028: 		if portScanConf.HasPrivileged {
1029: 			scanner.AddOptions(nmap.WithPrivileged())
1030: 		} else {
1031: 			scanner.AddOptions(nmap.WithUnprivileged())
1032: 		}
1033: 
1034: 		if portScanConf.SourcePort != "" {
1035: 			port, err := strconv.ParseUint(portScanConf.SourcePort, 10, 16)
1036: 			if err != nil {
1037: 				return []string{}, xerrors.Errorf("failed to strconv.ParseUint(%s, 10, 16) = %w", portScanConf.SourcePort, err)
1038: 			}
1039: 			scanner.AddOptions(nmap.WithSourcePort(uint16(port)))
1040: 		}
1041: 
1042: 		cmd := []string{baseCmd}
1043: 		if strings.Contains(ip, ":") {
1044: 			scanner.AddOptions(nmap.WithTargets(ip[1:len(ip)-1]), nmap.WithPorts(ports...), nmap.WithIPv6Scanning())
1045: 			cmd = append(cmd, "-p", strings.Join(ports, ","), ip[1:len(ip)-1])
1046: 		} else {
1047: 			scanner.AddOptions(nmap.WithTargets(ip), nmap.WithPorts(ports...))
1048: 			cmd = append(cmd, "-p", strings.Join(ports, ","), ip)
1049: 		}
1050: 
1051: 		l.log.Debugf("Executing... %s", strings.Replace(strings.Join(cmd, " "), "\n", "", -1))
1052: 		result, warnings, err := scanner.Run()
1053: 		if err != nil {
1054: 			return []string{}, xerrors.Errorf("unable to run nmap scan: %w", err)
1055: 		}
1056: 
1057: 		if warnings != nil {
1058: 			l.log.Warnf("nmap scan warnings: %s", warnings)
1059: 		}
1060: 
1061: 		for _, host := range result.Hosts {
1062: 			if len(host.Ports) == 0 || len(host.Addresses) == 0 {
1063: 				continue
1064: 			}
1065: 
1066: 			for _, port := range host.Ports {
1067: 				if strings.Contains(string(port.Status()), string(nmap.Open)) {
1068: 					scanDest := fmt.Sprintf("%s:%d", ip, port.ID)
1069: 					listenIPPorts = append(listenIPPorts, scanDest)
1070: 				}
1071: 			}
1072: 		}
1073: 	}
1074: 
1075: 	return listenIPPorts, nil
1076: }
