1078: func formatNmapOptionsToString(conf *config.PortScanConf) string {
1079: 	cmd := []string{conf.ScannerBinPath}
1080: 	if len(conf.ScanTechniques) != 0 {
1081: 		for _, technique := range conf.ScanTechniques {
1082: 			cmd = append(cmd, "-"+technique)
1083: 		}
1084: 	}
1085: 
1086: 	if conf.SourcePort != "" {
1087: 		cmd = append(cmd, "--source-port "+conf.SourcePort)
1088: 	}
1089: 
1090: 	if conf.HasPrivileged {
1091: 		cmd = append(cmd, "--privileged")
1092: 	}
1093: 
1094: 	return strings.Join(cmd, " ")
1095: }
