1097: func (l *base) setScanTechniques() (func(*nmap.Scanner), error) {
1098: 	scanTechniques := l.getServerInfo().PortScan.GetScanTechniques()
1099: 
1100: 	if len(scanTechniques) == 0 {
1101: 		if l.getServerInfo().PortScan.HasPrivileged {
1102: 			return nmap.WithSYNScan(), nil
1103: 		}
1104: 		return nmap.WithConnectScan(), nil
1105: 	}
1106: 
1107: 	for _, technique := range scanTechniques {
1108: 		switch technique {
1109: 		case config.TCPSYN:
1110: 			return nmap.WithSYNScan(), nil
1111: 		case config.TCPConnect:
1112: 			return nmap.WithConnectScan(), nil
1113: 		case config.TCPACK:
1114: 			return nmap.WithACKScan(), nil
1115: 		case config.TCPWindow:
1116: 			return nmap.WithWindowScan(), nil
1117: 		case config.TCPMaimon:
1118: 			return nmap.WithMaimonScan(), nil
1119: 		case config.TCPNull:
1120: 			return nmap.WithTCPNullScan(), nil
1121: 		case config.TCPFIN:
1122: 			return nmap.WithTCPFINScan(), nil
1123: 		case config.TCPXmas:
1124: 			return nmap.WithTCPXmasScan(), nil
1125: 		}
1126: 	}
1127: 
1128: 	return nil, xerrors.Errorf("Failed to setScanTechniques. There is an unsupported option in ScanTechniques.")
1129: }
