1261: 	for pid := range pidNames {
1262: 		stdout := ""
1263: 		stdout, err = l.lsProcExe(pid)
1264: 		if err != nil {
1265: 			l.log.Debugf("Failed to exec ls -l /proc/%s/exe err: %+v", pid, err)
