1267: 		}
1268: 		s, err := l.parseLsProcExe(stdout)
1269: 		if err != nil {
1270: 			l.log.Debugf("Failed to parse /proc/%s/exe: %+v", pid, err)
1271: 			continue
1272: 		}
1273: 		pidLoadedFiles[pid] = append(pidLoadedFiles[pid], s)
1274: 
1275: 		stdout, err = l.grepProcMap(pid)
1276: 		if err != nil {
1277: 			l.log.Debugf("Failed to exec /proc/%s/maps: %+v", pid, err)
1278: 			continue
1279: 		}
1280: 		ss := l.parseGrepProcMap(stdout)
1281: 		pidLoadedFiles[pid] = append(pidLoadedFiles[pid], ss...)
1282: 	}
1283: 
1284: 	pidListenPorts := map[string][]models.PortStat{}
1285: 	stdout, err = l.lsOfListen()
1286: 	if err != nil {
1287: 		// warning only, continue scanning
1288: 		l.log.Warnf("Failed to lsof: %+v", err)
