1315: 			procName = pidNames[pid]
1316: 		}
1317: 		proc := models.AffectedProcess{
1318: 			PID:             pid,
1319: 			Name:            procName,
1320: 			ListenPortStats: pidListenPorts[pid],
1321: 		}
1322: 
1323: 		for name := range uniq {
