func TestRegression_IncompleteScanScopeControl(t *testing.T) {
	// Location: scanner/base.go, function AnalyzeLibraries, lines 669-728
	// The code creates a disabledAnalyzers list to disable non-application scanners

	disabledAnalyzers := []analyzer.Type{
		// OS Family Detection
		analyzer.TypeOSRelease,
		analyzer.TypeAlpine,
		analyzer.TypeAmazon,
		analyzer.TypeCBLMariner,
		analyzer.TypeDebian,
		analyzer.TypePhoton,
		analyzer.TypeCentOS,
		analyzer.TypeRocky,
		analyzer.TypeAlma,
		analyzer.TypeFedora,
		analyzer.TypeOracle,
		analyzer.TypeRedHatBase,
		analyzer.TypeSUSE,
		analyzer.TypeUbuntu,

		// OS Package Management
		analyzer.TypeApk,
		analyzer.TypeDpkg,
		analyzer.TypeDpkgLicense,
		analyzer.TypeRpm,
		analyzer.TypeRpmqa,

		// OS Package Repository
		analyzer.TypeApkRepo,

		// Image Config
		analyzer.TypeApkCommand,

		// Structured Config
		analyzer.TypeYaml,
		analyzer.TypeJSON,
