func testAnalyzerGroupCreation(disabledAnalyzers []analyzer.Type) error {
	// This demonstrates the scanner scope control
	// The analyzer group is created in scanner/base.go line 729:
	// anal := analyzer.NewAnalyzerGroup(analyzer.GroupBuiltin, disabledAnalyzers)

