	// The stale import location
	staleImportPath := "github.com/aquasecurity/trivy/pkg/fanal/analyzer/os"

	// In newer Trivy versions, this module location has changed
	// The OS constants like os.RedHat, os.Debian, etc. may have moved or been refactored

